import React, { useState, useEffect } from 'react';
import Home from './Home';
import FarmerAdd from './FarmerAdd';
import BuyerBrowse from './BuyerBrowse';

function App() {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('kisan_user')));
  const [screen, setScreen] = useState('home');
  const [products, setProducts] = useState([]);
  const [loginData, setLoginData] = useState({ name: '', phone: '' });

  useEffect(() => {
    fetch('http://127.0.0.1:5000/api/products')
      .then(res => res.json())
      .then(data => setProducts(data));
  }, [screen]);

  const handleLogin = (e) => {
    e.preventDefault();
    fetch('http://127.0.0.1:5000/api/login', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(loginData)
    })
    .then(res => res.json())
    .then(userData => {
      localStorage.setItem('kisan_user', JSON.stringify(userData));
      setUser(userData);
    });
  };

  const saveCrop = (newCrop) => {
    const finalData = { ...newCrop, farmer_id: user.id, farmer_name: user.name, farmer_phone: user.phone };
    fetch('http://127.0.0.1:5000/api/products', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(finalData)
    }).then(() => setScreen('home'));
  };

  if (!user) {
    return (
      <div className="min-h-screen bg-green-600 flex flex-col items-center justify-center p-10">
        <h1 className="text-white text-5xl font-black mb-10">KisanMarket</h1>
        <form onSubmit={handleLogin} className="w-full max-w-md space-y-6">
          <input required type="text" placeholder="Your Name (तुमचे नाव)" className="w-full p-6 rounded-3xl text-2xl border-none shadow-xl" 
            onChange={e => setLoginData({...loginData, name: e.target.value})} />
          <input required type="number" placeholder="Phone (फोन नंबर)" className="w-full p-6 rounded-3xl text-2xl border-none shadow-xl" 
            onChange={e => setLoginData({...loginData, phone: e.target.value})} />
          <button type="submit" className="w-full bg-orange-500 text-white py-6 rounded-3xl text-3xl font-black shadow-2xl">START (सुरु करा)</button>
        </form>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {screen === 'home' && <Home onSellClick={() => setScreen('sell')} onBuyClick={() => setScreen('buy')} userName={user.name} />}
      {screen === 'sell' && <FarmerAdd onBack={() => setScreen('home')} onFinish={saveCrop} />}
      {screen === 'buy' && <BuyerBrowse onBack={() => setScreen('home')} items={products} />}
    </div>
  );
}

export default App;
